OpenFocusedDirectory() {
    try {
        hwnd := WinExist("A")
        if !hwnd
            return

        pid := WinGetPID("ahk_id " hwnd)
        processName := WinGetProcessName("ahk_id " hwnd)

        finalPath := ""

        ; 1. Try WMI to get command line (Best for scripts)
        try {
            for proc in ComObjGet("winmgmts:").ExecQuery("Select CommandLine from Win32_Process Where ProcessId = " pid) {
                cmdLine := proc.CommandLine
                if !cmdLine
                    continue

                ; Look for paths in quotes first
                if RegExMatch(cmdLine, 'i)"([^"]+\.(py|ps1|ahk|bat|cmd))"', &match)
                    finalPath := match[1]
                ; Then look for unquoted paths after space
                else if RegExMatch(cmdLine, 'i)\s([^\s]+\.(py|ps1|ahk|bat|cmd))(\s|$)', &match)
                    finalPath := match[1]
            }
        }

        ; 2. Fallback: Check window title for a path (Good for editors/IDEs)
        if (finalPath == "") {
            title := WinGetTitle("ahk_id " hwnd)
            ; Look for something that looks like a Windows path with common extensions
            if RegExMatch(title, 'i)([a-zA-Z]:\\[^:<>|"?*]+\.[a-zA-Z0-9]+)', &match) {
                if FileExist(match[1])
                    finalPath := match[1]
            }
        }

        ; 3. Final Fallback: Use the executable path
        if (finalPath == "") {
            try {
                finalPath := WinGetProcessPath("ahk_id " hwnd)
            }
        }

        if (finalPath != "") {
            SplitPath(finalPath, , &dir)
            if (dir != "" && DirExist(dir))
                Run('explorer.exe "' . dir . '"')
            else if (dir == "" && FileExist(finalPath)) {
                ; If it's just a file name or path failed SplitPath, try to get dir from full path
                dir := RegExReplace(finalPath, "\\[^\\]+$")
                if DirExist(dir)
                    Run('explorer.exe "' . dir . '"')
            }
        }
    }
}

