CP_RED = "#FF003C"
CP_DIM = "#3a3a3a"
CP_TEXT = "#E0E0E0"
CP_SUBTEXT = "#808080"


class MainWindow(QMainWindow):
    def __init__(self):
        super().__init__()
        self.setStyleSheet(f"QMainWindow {{ background-color: {CP_BG}; }}")
        # ... your UI setup


if __name__ == "__main__":
    app = QApplication([])
    app.setStyle("Fusion")  # Important for consistent styling
    window = MainWindow()
    window.show()
    app.exec()
```


