MergeTab(hNewWnd) {
    if !WinExist(hNewWnd)
        return

    allExplorers := WinGetList("ahk_class CabinetWClass")
    targetWnd := 0

    for hWnd in allExplorers {
        if (hWnd != hNewWnd) {
            targetWnd := hWnd
            break
        }
    }

    if (!targetWnd)
        return

    newPath := ""
    Loop 10 {
        try {
            sh := ComObject("Shell.Application")
            for window in sh.Windows {
                try {
                    if (window.hwnd == hNewWnd) {
                        try {
                            newPath := window.Document.Folder.Self.Path
                        } catch {
                            newPath := window.LocationURL
                        }
                        break
                    }
                }
            }
        }
        if (newPath != "")
            break
        Sleep(100)
    }

    if (newPath == "")
        return

    try {
        WinClose(hNewWnd)
        WinActivate(targetWnd)
        Sleep(100)
        Send("^t")
        Sleep(200)
        Send("{Esc}")
        Sleep(50)
        Send("!d")
        Sleep(50)
        Send("^a")
        Sleep(50)
        SendText(newPath)
        Sleep(100)
        Send("{Enter}")
        Sleep(50)
        Send("{Esc}")
